#!/usr/bin/env node
// Generates src/admin-assets.ts from the editable admin UI source files in src/ui/.
// Run via `npm run build:admin` (also wired as a pre-hook for check/test/dev/deploy).
// The generated file is committed so tsc, vitest, and wrangler all consume a plain .ts.

import { readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const root = join(dirname(fileURLToPath(import.meta.url)), "..");
const uiDir = join(root, "src", "ui");
const outFile = join(root, "src", "admin-assets.ts");

const assets = [
  { name: "ADMIN_HTML", file: "admin.html" },
  { name: "ADMIN_CSS", file: "admin.css" },
  { name: "ADMIN_JS", file: "admin.js" },
];

const banner =
  "// AUTOGENERATED by scripts/build-admin-assets.mjs from src/ui/*. Do not edit by hand.\n" +
  "// Edit src/ui/admin.html, src/ui/admin.css, src/ui/admin.js and re-run `npm run build:admin`.\n\n";

const body = assets
  .map(({ name, file }) => {
    const contents = readFileSync(join(uiDir, file), "utf8");
    return `export const ${name} = ${JSON.stringify(contents)};\n`;
  })
  .join("\n");

writeFileSync(outFile, banner + body, "utf8");
console.log(`Wrote ${outFile}`);
